Additionally, you can implement real-time notifications using WebSockets:

Backend (WebSocket integration):
```javascript
const WebSocket = require('ws');

// Create WebSocket server
const wss = new WebSocket.Server({ port: 8080 });

wss.on('connection', (ws) => {
  console.log('Client connected');

  ws.on('close', () => {
    console.log('Client disconnected');
  });
});

// Broadcast notification to all connected clients
const broadcastNotification = (notification) => {
  wss.clients.forEach((client) => {
    if (client.readyState === WebSocket.OPEN) {
      client.send(JSON.stringify(notification));
    }
  });
};

// When a pest or disease is detected
const detectPestOrDisease = async (pestData) => {
  const notification = await createNotification(
    'Pest/Disease Detected',
    `A ${pestData.name} has been detected in your farm.`
  );
  broadcastNotification(notification);
};
```

Frontend (WebSocket connection):
```javascript
useEffect(() => {
  const ws = new WebSocket('ws://localhost:8080');

  ws.onmessage = (event) => {
    const notification = JSON.parse(event.data);
    setNotifications([notification, ...notifications]);
  };

  return () => ws.close();
}, []);
```

This integration will allow users to receive real-time alerts and notifications about detected pests and diseases on their farm, and mark them as read when they view them.
